RETURNING id;

INSERT INTO chapter_versions (chapter_id, project_id, version_number, version_type, title, body_markdown, summary, word_count, model_provider, model_name, created_by_agent)
VALUES ($1, $2, 1, 'draft', $3, $4, $5, $6, 'claude', 'claude-code', 'draft_writer')
RETURNING id;

UPDATE chapters SET current_version_id = (
  SELECT id FROM chapter_versions WHERE chapter_id = $1 ORDER BY version_number DESC LIMIT 1
)
WHERE id = $1;

UPDATE generation_jobs
SET status = 'draft_created', chapter_id = $1, updated_at = now()
WHERE id = $7;

