// ============================================================
// Review Aggregator — 聚合 7 个审稿 Agent 结果并输出决策。
//
// 输入：$input.all() — 来自 7 个并行 review HTTP Request 节点。
// 每个 item 可能是 OpenAI chat/completions response 或
// 已经解析好的 review JSON（取决于上游节点）。
//
// 聚合规则（按优先级）：
//   1. safety_reviewer pass=false → needs_human_review
//   2. 任一有 blocking_issues → revise
//   3. avg_score >= quality_threshold 且无 blocking → publish_ready
//   4. avg_score < quality_threshold → revise
//   5. revise_count >= max_revise_count 仍未通过 → needs_human_review
//
// final_score 规则：
//   - safety failed  → min(average_score, 40)
//   - has blocking   → min(average_score, 74)
//   - all pass       → average_score
// ============================================================

const allReviews = $input.all();
const reviewData = [];

// ---- 1. Parse each agent's output ----
for (const item of allReviews) {
  try {
    const j = item.json;
    // OpenAI chat/completions format
    if (j.choices?.[0]?.message?.content) {
      const parsed = JSON.parse(j.choices[0].message.content);
      reviewData.push(parsed);
    }
    // Already parsed JSON with agent_name
    else if (j.agent_name) {
      reviewData.push(j);
    }
    // Nested inside data (HTTP Request node response)
    else if (j.data?.agent_name) {
      reviewData.push(j.data);
    }
    else {
      reviewData.push({
        agent_name: 'unknown',
        score: 0,
        pass: false,
        blocking_issues: [{ id: 'PARSE_ERR', severity: 'high', issue: 'Unable to parse review output' }],
        minor_issues: [],
        recommendations: []
      });
    }
  } catch (e) {
    reviewData.push({
      agent_name: 'parse_error',
      score: 0,
      pass: false,
      blocking_issues: [{ id: 'PARSE_ERR', severity: 'high', issue: `Failed to parse review: ${e.message}` }],
      minor_issues: [],
      recommendations: []
    });
  }
}

// ---- 2. Identify special agents ----
const safetyReview = reviewData.find(r => r.agent_name === 'safety_reviewer');

// ---- 3. Calculate average_score ----
const scores = reviewData.map(r => r.score).filter(s => typeof s === 'number' && !isNaN(s));
const averageScore = scores.length > 0
  ? Math.round((scores.reduce((a, b) => a + b, 0) / scores.length) * 100) / 100
  : 0;

// ---- 4. Collect issues ----
const allBlocking = [];
const allMinor = [];
const recommendationsByAgent = {};

for (const r of reviewData) {
  (r.blocking_issues || []).forEach(issue => {
    allBlocking.push({ ...issue, agent_name: r.agent_name });
  });
  (r.minor_issues || []).forEach(issue => {
    allMinor.push({ ...issue, agent_name: r.agent_name });
  });
  if (r.recommendations && r.recommendations.length > 0) {
    recommendationsByAgent[r.agent_name] = r.recommendations;
  }
}

// ---- 5. Determine decision ----
const hasBlocking = allBlocking.length > 0;
const safetyFailed = safetyReview && safetyReview.pass === false;

// Get revise_count and max from writing brief context
const briefNode = $('Build Writing Brief').first();
const reviseCount = briefNode?.json?.revise_count ?? $input.first().json.revise_count ?? 0;
const maxRevise = briefNode?.json?.max_revise_count ?? $input.first().json.max_revise_count ?? 2;
const qualityThreshold = briefNode?.json?.quality_threshold ?? $input.first().json.quality_threshold ?? 85;

let decision;
if (safetyFailed) {
  decision = 'needs_human_review';
} else if (reviseCount >= maxRevise && hasBlocking) {
  decision = 'needs_human_review';
} else if (hasBlocking) {
  decision = 'revise';
} else if (averageScore >= qualityThreshold) {
  decision = 'publish_ready';
} else {
  decision = 'revise';
}

// ---- 6. Calculate final_score ----
let finalScore;
if (safetyFailed) {
  finalScore = Math.min(averageScore, 40);
} else if (hasBlocking) {
  finalScore = Math.min(averageScore, 74);
} else {
  finalScore = averageScore;
}
finalScore = Math.round(finalScore * 100) / 100;

// ---- 7. publish_allowed ----
const publishAllowed = decision === 'publish_ready';

// ---- 8. Build output ----
return [{
  json: {
    // IDs from Prepare Review Input
    chapter_id: $('Prepare Review Input').first().json.chapter_id,
    version_id: $('Prepare Review Input').first().json.version_id,

    // Scores
    average_score: averageScore,
    final_score: finalScore,

    // Decision
    decision: decision,
    publish_allowed: publishAllowed,

    // Status flags
    safety_pass: !safetyFailed,
    has_blocking: hasBlocking,
    all_pass: reviewData.every(r => r.pass !== false),

    // Merged issues
    blocking_issues: allBlocking,
    minor_issues: allMinor,
    must_fix: allBlocking.filter(i => i.severity === 'high' || safetyFailed),

    // Grouped recommendations
    recommendations: recommendationsByAgent,

    // Raw review data (for saving to DB)
    reviews: reviewData,

    // Summary
    agent_count: reviewData.length,
    blocking_count: allBlocking.length,
    minor_count: allMinor.length,
    safety_passed: !safetyFailed
  }
}];

